const message = $("Get a message").first().json;

const getHeader = (name) => {
  const headers = message.payload?.headers || [];

  const match = headers.find(
    (header) =>
      String(header.name || "").toLowerCase() === name.toLowerCase()
  );

  return match?.value || "";
};

const cleanText = (value = "") => {
  return String(value)
    .replace(/\r/g, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
};

const stripHtml = (html = "") => {
  return String(html)
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<[^>]*>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .trim();
};

const getBestBody = () => {
  if (message.text) {
    return cleanText(message.text);
  }

  if (message.textAsHtml) {
    return cleanText(stripHtml(message.textAsHtml));
  }

  if (message.html) {
    return cleanText(stripHtml(message.html));
  }

  if (message.snippet) {
    return cleanText(message.snippet);
  }

  return "";
};

const fromRaw = String(
  getHeader("From") ||
  message.from?.text ||
  message.From ||
  ""
);

const subject = String(
  getHeader("Subject") ||
  message.subject ||
  message.Subject ||
  ""
);

const body = getBestBody();

const emailMatch =
  fromRaw.match(/<([^>]+)>/) ||
  fromRaw.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);

const senderEmail = Array.isArray(emailMatch)
  ? emailMatch[1] || emailMatch[0]
  : "";

const senderName = fromRaw
  .replace(/<[^>]+>/g, "")
  .replace(/"/g, "")
  .trim() || senderEmail;

return [
  {
    json: {
      messageId: message.id || "",
      threadId: message.threadId || "",
      senderName,
      senderEmail,
      subject,
      body,
      receivedAt: new Date().toISOString(),
      today: new Date().toISOString().slice(0, 10),
    },
  },
];

const mail = $("Normalize Email").first().json;
const rawAiOutput = $json.output || "{}";

const parseAiOutput = () => {
  try {
    return typeof rawAiOutput === "string" ? JSON.parse(rawAiOutput) : rawAiOutput;
  } catch {
    return {};
  }
};

const ai = parseAiOutput();

const createTaskId = () => {
  return `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
};

const normalizePriority = (priority = "") => {
  const value = String(priority).toLowerCase().trim();

  if (value.includes("urgent") || value.includes("critical") || value.includes("high")) {
    return "urgent";
  }

  if (value.includes("low") || value.includes("minor")) {
    return "low";
  }

  return "medium";
};

const normalizeCategory = (category = "") => {
  return category === "Technical Task" ? "Technical Task" : "User Story";
};

const normalizeDueDate = (dueDate = "") => {
  const value = String(dueDate).trim();

  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) {
    return value;
  }

  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  return tomorrow.toISOString().slice(0, 10);
};

const normalizeSubtasks = (subtasks = []) => {
  if (!Array.isArray(subtasks)) return [];

  return subtasks
    .map((subtask, index) => {
      const text = typeof subtask === "string" ? subtask : subtask.text;

      return {
        id: `subtask-${Date.now()}-${index}`,
        text: String(text || "").trim(),
        done: false
      };
    })
    .filter((subtask) => subtask.text.length > 0);
};

return [
  {
    json: {
      id: createTaskId(),
      title: String(ai.title || mail.subject || "New Stakeholder Request").trim(),
      description: String(ai.description || mail.body || "").trim(),
      category: normalizeCategory(ai.category),
      priority: normalizePriority(ai.priority),
      status: "triage",
      dueDate: normalizeDueDate(ai.dueDate),
      createdAt: new Date().toISOString(),

      threadId: mail.threadId,
      messageId: mail.messageId,

      creatorType: "external",
      creatorName: mail.senderName,
      creatorEmail: mail.senderEmail,

      isEmailRequest: true,
      aiGenerated: true,
      requestSource: "email",

      assignedTo: [],
      teamMembers: [],
      subtasks: normalizeSubtasks(ai.subtasks),

      requestStatus: "new",
      requestReceivedAt: mail.receivedAt
    }
  }
];

const staticData = $getWorkflowStaticData("global");

const LIMIT = 10;
const today = new Date().toISOString().split("T")[0];

staticData.emailCounter ??= {};
staticData.emailCounter[today] ??= 0;

const currentCount = Number(staticData.emailCounter[today]) || 0;
const limitReached = currentCount >= LIMIT;

if (!limitReached) {
  staticData.emailCounter[today] = currentCount + 1;
}

return [
  {
    json: {
      today,
      count: staticData.emailCounter[today],
      limitReached,
      remaining: Math.max(0, LIMIT - staticData.emailCounter[today]),
    },
  },
];
